class Solution:
  def delete_duplicates(self, nums: list[int]) -> list[int]:
      i = 0
      while i < len(nums) - 1:
        if nums[i] == nums[i + 1]:
          nums.pop(i)
          i -= 1
        i += 1
      return nums

