#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    vector<int> delete_duplicates(vector<int>& nums) {
      vector<int> result;
      for (int num : nums) {
        if (result.empty() || num != result.back()) {
          result.push_back(num);
        }
      }
      return result;
    }
};
int main() {
    Solution solution;
    vector<int> nums = {4, 2, 5, 2, 6, 5, 1};
    auto result = solution.delete_duplicates(nums);
    for (int num : result) {
        cout << num << ' ';n    }
    cout << endl;
    return 0;
}
